function makeId(en) {
  return 'dev-' + en.toLowerCase().replace(/['\u2019]+/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export const devPhrases = raw.map(([en, zh, category, sentence]) => ({
  id: makeId(en),
  en, zh, category,
  img: null,
  level: 'dev',
  sentence: sentence || '', sentenceZh: '',
  ja: null, jaSentence: null,
  ipa: '', pinyin: '', jaReading: null,
}));

function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export const devPhrasesShuffled = shuffleArray(devPhrases);
